function DJServices() {
  const djs = [
    {
      name: "DJ Karim",
      experience: "8 Years",
      service: "Wedding DJ Services",
      package:
        "Wedding music setup, sound systems, party lighting, and live DJ entertainment.",
      contact: "djkarim@email.com",
      price: "$700 event",
      image: "https://cdn-icons-png.flaticon.com/512/3659/3659898.png",
    },

    {
      name: "Royal Beats",
      experience: "6 Years",
      service: "Luxury Wedding Entertainment",
      package:
        "Professional DJ performance, premium sound system, dance floor lighting, and event hosting.",
      contact: "royalbeats@email.com",
      price: "$1200 event",
      image: "https://cdn-icons-png.flaticon.com/512/1048/1048953.png",
    },

    {
      name: "Party Vibes",
      experience: "5 Years",
      service: "Wedding Music and Lighting",
      package:
        "Wedding playlists, party lighting effects, live music mixing, and guest entertainment.",
      contact: "partyvibes@email.com",
      price: "$850 event",
      image: "https://cdn-icons-png.flaticon.com/512/3079/3079167.png",
    },
  ];

  function requestDJ(name) {
    alert("Your request has been sent to " + name);
  }

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>DJ Services</h1>

        <p>
          Discover professional DJs and entertainment services for weddings,
          music, lighting, and unforgettable celebrations.
        </p>
      </div>

      <section className="cards">
        {djs.map((dj, index) => (
          <div className="card" key={index}>
            <img
              src={dj.image}
              alt={dj.name}
              className="service-image"
            />

            <h3>{dj.name}</h3>

            <p><strong>Service:</strong> {dj.service}</p>
            <p><strong>Package Includes:</strong> {dj.package}</p>
            <p><strong>Experience:</strong> {dj.experience}</p>
            <p><strong>Email:</strong> {dj.contact}</p>
            <p><strong>Price:</strong> {dj.price}</p>

            <button
              className="request-btn"
              onClick={() => requestDJ(dj.name)}
            >
              Request Service
            </button>
          </div>
        ))}
      </section>
    </section>
  );
}

export default DJServices;
